import { Theme } from "../Theme/types";

const lightThemeColors = {
  primary: "#e60800",
  secondary: "#31081F",
  dark: "#580100",
  text: "#2C2C31",
  accent: "#FFEBEB",
};

const darkThemeColors = {
  primary: "#31081F",
  secondary: "#e60800",
  dark: "#580100",
  text: "#FFEBEB",
  accent: "#2C2C31",
};

export const getColors = (theme: Theme) =>
  theme === Theme.LIGHT ? lightThemeColors : darkThemeColors;
